CACHE_TTL_SECONDS = int(os.environ.get("CACHE_TTL_SECONDS", "604800"))  # 7 days
ALLOWLIST_DOMAINS = os.environ.get("ALLOWLIST_DOMAINS", "").strip()  # comma-separated, optional
